INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00063', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「瑞典政府每月給國民五萬臺幣左右的救濟金，讓國民不愁吃穿，但要求一定要上大學，或學一種技 能。安逸的生活卻讓瑞典人反質疑自己存在的價值而自殺。每年有兩千多人自殺，是自殺率最高的國 家之一。由此看來『北歐天堂』可能不是真正的天堂，一定有比物質無虞更重要的東西。」 根據上文，下列選項何者正確？', '["北歐物產豐盛，加上國家福利完善，令人民無所適從", "瑞典要求國民要上大學與學習技能，不工作就能領補助", "世界上最重要的東西不是擁有物質，而是生命意義的創造", "瑞典是自殺率頗高的國家，源於政府要求強迫上大學的壓力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00064', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '文化部與教育部共同主辦「看見藝術力——文化體驗教育展」：「開幕式在恆春國小與車城國小師生聯 合表演恆春民謠組曲下揭開。該計畫廣邀各領域的藝文工作者，藉由自身藝文專業的轉化，發展出獨 具特色的體驗內容，讓文化體驗進入學校正規課程，讓孩子們用眼睛看、用手碰觸及身體律動，感受 文化藝術帶來的五感體驗，目前累積受惠學子近8萬人次。」 根據上文，下列選項何者正確？', '["為推廣藝文，應盡力衝高人次，才能達到效益最大化", "藝文根植於社會，應從在地的民謠、歌舞、戲劇出發", "透過體驗式的藝文觀賞經驗，從校園推動藝文普及化", "透過系統的教學與測驗，進一步將藝文納入正規課程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00065', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「遠處的山巒一片青翠，布滿針葉林，一道峭壁看似老人的側面。多數時候，我們無暇欣賞風景，因 為路況太差，需要全神貫注。一整天的路上沒有遇到其他車輛，經過一個小村落時，村民熱情歡迎我 們，彷彿我們是來解救被敵軍圍困的軍隊。我們小心地駕車穿過，所有人都對我們歡呼。一群小男孩 騎腳踏車一路跟著我們，直到離開村落，我們才向他們揮手道別。」 根據上文，關於作者沿途的經歷，敘述正確的是：', '["因視線不明朗而意外經過村落", "因路況不佳，無法專心看風景", "沿途有戰火波及，故行車稀少", "所有人一路尾隨在車後方送別"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00066', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「主題並不在於蒐集事件，因為事件本身能提供的趣味並不算多。重要的是從中選擇，在深厚的現實 中，掌握真正的事實。從攝影來看，最微小的東西也可能成為偉大的主題，與人類有關的枝微末節也 可以成為樂章的主旋律。」 根據上文，下列選項何者最符合文意？', '["賦予畫面豐富的節奏感", "在現實中淘選事物真相", "瑣碎事物難以展現觀點", "善於記錄重大社會現實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00067', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '聖修伯里說：「如果你想造一艘船，不要鼓勵人們去伐木、去分配工作、去發號施令。領導者應該做 的是，教人們去渴望大海的寬廣無邊和高深莫測。」 根據上文，領導者的重要任務在於：', '["描繪願景", "建立制度", "責任分工", "提供獎賞"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00068', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「裝盆並非填塞，須依材質濃淡逐層排砌。底層要放質瘠味淡的瘦物，例如蘿蔔、芋頭、枝竹（長條 豆皮）和豬皮，以濡染吸收油汁；中層要放香濃味厚之物，如紅炆（燜）豬肉、芹菜炒魷魚，以增益 滋味香氣；上層才擺上冬菇、燒鴨、煎蝦和鯪魚球等好料，以示體面美觀。乍看無甚技巧，然而要做 得豐美交融，多而不亂，卻很費功夫，關鍵在於中間那層紅炆豬肉。」 根據上述關於「盆菜」的作法，敘述正確的是：', '["盆菜作工精細，食材的前置處理複雜", "紅炆豬肉是盆菜成功與否的關鍵因素", "最上層的好料體面美觀，但並不美味", "享用時由上往下的口味將是由淡至濃"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00069', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '賈伯斯說：「『記住你即將死去』是我一生中遇到的最重要箴言，它幫我指明了生命中重要的選擇，因 為幾乎所有的事情，包括榮譽、驕傲，以及對難堪和失敗的恐懼，這些在死亡面前都會消失。我看到 的是留下來真正重要的東西，『記住你即將死去』是你做任何事情都不會虛度浪費的唯一方向。」 根據上文，下列選項何者正確？', '["在死亡的威脅之下，爭取榮耀才能擺脫陰影束縛", "在死亡面前不要虛度光陰，創造自己人生的價值", "強調生命存在的重要，否則一切最後將化為烏有", "死亡沒有想像中可怕，要與死亡展開坦誠的對話"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00070', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「對畫家來說，盡情使用藍色根本像做夢一樣。另一種被用作藍色顏料的礦物——藍銅礦的價格也非 常昂貴。文藝復興時期就有使用『鈷玻璃』（磨碎）來取代群青，但都不耐久。1704年的某天，這樣 的情況出現了轉機。在柏林的煉金術師工房，調和師偶然地做出了藍色的顏料。這就是近代最早的人 工顏料『普魯士藍』。」 根據上文，下列選項何者最接近文意？', '["18世紀以後的畫作，出現藍色的比例可能增加許多", "中世紀的畫家與當代畫家相比，比較能憑靈感發揮", "1704年以前，繪製森林的畫作成本比海洋的畫作高", "即便藍色顏料逐漸普遍，仍因原料的關係容易褪色"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00071', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「這棵蓮霧已經二十年了，二十年間，這棵樹在這兒動也沒動過，而且它的葉子年年新鮮翠綠。我認 為這種生存的方法是很美的，這點在我們的生活中有嗎？我們在藝術、學問中打轉，是否遺忘了什麼？ 那座山也是！數十年，數百年來，它都是那麼奕奕地存在著，和這些比起來，我覺得我們都像患了夢 遊症的人。」 根據上文，下列選項最接近作者旨趣的是：', '["回歸田園，以自然萬物為芻狗", "人應該像山與樹一樣強大堅韌", "從事藝術與學問，應堅持到底", "悠遊大自然，比鑽研一切重要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00072', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「我們的祖先都來自海洋。是什麼樣的進化或異化過程，讓我們如此疏離、畏懼海洋？只能望著嬉游 的鯨豚或浮冰上的海豹興嘆？其實，在每個人身上密布的六萬哩血管裡還循環著六公升的海洋，溶解 並勤奮地輸送著氧。那也許是從單細胞時代開始，我們就一點一滴儲藏起來的鄉愁。」 根據上文，下列選項何者最接近文意？', '["人類對於海洋的依賴，一直潛藏在內心深處，成為生命的一部分", "點點滴滴累積的哀愁，由細流匯集成海，最終像海一樣深不可測", "人心的冷漠變化，使我們不再保持對海洋生物有悲憫的赤子之心", "生態不斷遭受破壞，鯨豚、海豹的身影逐漸陌生，令人不勝唏噓"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
